#!/usr/bin/env node
// Prepends a "do not edit" header to the RTK Query codegen output. Orval
// emits its own header automatically; @rtk-query/codegen-openapi does not.
// Keeping the header on disk (rather than in a runtime-detected wrapper)
// means human reviewers see the generated marker in plain diffs and the
// drift gate's `git diff` output makes the regeneration intent obvious.

import { readFileSync, writeFileSync } from 'node:fs'
import { resolve } from 'node:path'
import { cwd } from 'node:process'

const HEADER = `/**
 * Generated by @rtk-query/codegen-openapi.
 * Do not edit manually.
 *
 * Source spec: ../backend/openapi/swagger.json (emitted by the backend's
 * EmitOpenApi MSBuild target per DEC-066 / R-071). Re-run \`npm run codegen\`
 * after any backend DTO change; the drift gate (\`npm run codegen:check\`)
 * fails CI if this file diverges from the spec.
 */
`

const targets = ['./src/app/api/generated/rtk/api.ts']

for (const relPath of targets) {
  const filePath = resolve(cwd(), relPath)
  const content = readFileSync(filePath, 'utf8')
  if (content.startsWith('/**\n * Generated by @rtk-query/codegen-openapi')) {
    continue
  }
  writeFileSync(filePath, HEADER + content, 'utf8')
}
